const THEMES_CONFIG={home:{name:"Home - Multifaceted Identity",keywords:["multifaceted","identity","director","creator","peacekeeper"],colors:{base:{background:"#0a0f15",secondary:"#0d1820",text:"#e8eef5",textSecondary:"rgba(232, 238, 245, 0.65)"},accents:{primary:"#6ba3ff",secondary:"#00d9ff",tertiary:"#b84dff",gold:"#ffd700"},gradients:{prismatic:"linear-gradient(135deg, #6ba3ff, #00d9ff, #b84dff, #6ba3ff)",shimmer:"linear-gradient(90deg, #ffd700, #00d9ff, #6ba3ff)"}},animation:{entrance:"kaleidoscope",duration:1200,easing:"power2.inOut"}},journey:{name:"Journey - Timeline & Growth",keywords:["timeline","growth","evolution","expertise","career"],colors:{base:{background:"#0b0f1a",secondary:"#0f1429",text:"#dce4f0",textSecondary:"rgba(220, 228, 240, 0.65)"},accents:{primary:"#7c5cff",secondary:"#1fb8d4",tertiary:"#ff6b9d",gold:"#e8b44a"},gradients:{flow:"linear-gradient(180deg, #7c5cff, #1fb8d4, #ff6b9d)",path:"linear-gradient(90deg, #7c5cff, #1fb8d4)"}},animation:{entrance:"timeline-reveal",duration:1500,easing:"power3.inOut"}},creations:{name:"Creations - Artistic & Experimental",keywords:["art","creative","experimental","design","playful"],colors:{base:{background:"#120f0a",secondary:"#1a1410",text:"#f0ede8",textSecondary:"rgba(240, 237, 232, 0.65)"},accents:{primary:"#ff6b5a",secondary:"#ffa500",tertiary:"#ffdb58",quaternary:"#ff1493"},gradients:{artistic:"linear-gradient(45deg, #ff6b5a, #ffa500, #ffdb58, #ff1493)",warm:"linear-gradient(135deg, #ff6b5a, #ffa500)"}},animation:{entrance:"drift-rotate",duration:1e3,easing:"sine.inOut"}},odyssey:{name:"Odyssey - Poetic Narrative",keywords:["narrative","story","transformation","journey","peacekeeper"],colors:{base:{background:"#0f0c0a",secondary:"#1a1410",text:"#f5ede4",textSecondary:"rgba(245, 237, 228, 0.65)"},accents:{primary:"#d4a574",secondary:"#c97e6d",tertiary:"#9b6b4a",gold:"#f4d03f"},gradients:{narrative:"linear-gradient(135deg, #d4a574, #c97e6d, #9b6b4a)",ink:"linear-gradient(90deg, #d4a574, #c97e6d)"}},animation:{entrance:"unfold-reveal",duration:2e3,easing:"power1.inOut"}},connect:{name:"Connect - Network & Community",keywords:["connection","collaboration","community","reach","network"],colors:{base:{background:"#0f0d0a",secondary:"#161410",text:"#f0ede8",textSecondary:"rgba(240, 237, 232, 0.65)"},accents:{primary:"#d4a574",secondary:"#3dd5f3",tertiary:"#6bc34a",gold:"#ffc107"},gradients:{network:"linear-gradient(135deg, #d4a574, #3dd5f3, #6bc34a)",connection:"linear-gradient(90deg, #3dd5f3, #6bc34a)"}},animation:{entrance:"network-activate",duration:1200,easing:"power2.out"}}};function getTheme(pageName){return THEMES_CONFIG[pageName.toLowerCase()]||THEMES_CONFIG.home}function applyTheme(pageName){const theme=getTheme(pageName);const root=document.documentElement;root.style.setProperty("--theme-bg",theme.colors.base.background);root.style.setProperty("--theme-bg-secondary",theme.colors.base.secondary);root.style.setProperty("--theme-text",theme.colors.base.text);root.style.setProperty("--theme-text-secondary",theme.colors.base.textSecondary);root.style.setProperty("--theme-accent-primary",theme.colors.accents.primary);root.style.setProperty("--theme-accent-secondary",theme.colors.accents.secondary);root.style.setProperty("--theme-accent-tertiary",theme.colors.accents.tertiary);root.style.setProperty("--theme-gold",theme.colors.accents.gold);const gradientKeys=Object.keys(theme.colors.gradients);gradientKeys.forEach((key,index)=>{root.style.setProperty(`--theme-gradient-${index+1}`,theme.colors.gradients[key])});return theme}if(typeof module!=="undefined"&&module.exports){module.exports={THEMES_CONFIG:THEMES_CONFIG,getTheme:getTheme,applyTheme:applyTheme}}